import React, { useState } from 'react';

const AdminPanel = ({ rooms, archive, dailyLogs, threshold, setThreshold, users, setUsers }) => {
    const [view, setView] = useState('stats'); // 'stats', 'archive', 'users'
    const [newUser, setNewUser] = useState({ login: '', pass: '', role: 'staff' });

    // Функция добавления пользователя
    const addUser = () => {
        if (!newUser.login || !newUser.pass) return alert("Заполните логин и пароль");
        setUsers([...users, newUser]);
        setNewUser({ login: '', pass: '', role: 'staff' });
    };

    // Функция удаления пользователя
    const deleteUser = (login) => {
        if (login === 'admin') return alert("Главного админа нельзя удалить!");
        setUsers(users.filter(u => u.login !== login));
    };

    return (
        <div className="page-content fade-in">
            <h2 className="page-title">Management</h2>

            {/* Меню переключения */}
            <div className="threshold-buttons" style={{ marginBottom: '20px' }}>
                <button className={`t-btn ${view === 'stats' ? 'active' : ''}`} onClick={() => setView('stats')}>СЕГОДНЯ</button>
                <button className={`t-btn ${view === 'archive' ? 'active' : ''}`} onClick={() => setView('archive')}>АРХИВ</button>
                <button className={`t-btn ${view === 'users' ? 'active' : ''}`} onClick={() => setView('users')}>ПЕРСОНАЛ</button>
            </div>

            {/* Вкладка СТАТИСТИКА */}
            {view === 'stats' && (
                <>
                    <div className="admin-stats-grid">
                        <div className="stat-card">
                            <span className="stat-value" style={{color: 'var(--success)'}}>{rooms.filter(r => r.status === 'checked').length}</span>
                            <span className="stat-label">Проверено</span>
                        </div>
                        <div className="stat-card">
                            <span className="stat-value" style={{color: 'var(--danger)'}}>{rooms.filter(r => r.status === 'dnd').length}</span>
                            <span className="stat-label">DND</span>
                        </div>
                    </div>
                    <div className="admin-settings-section">
                        <h3>Лента действий</h3>
                        <div style={{ maxHeight: '200px', overflowY: 'auto', fontSize: '12px' }}>
                            {dailyLogs.map((log, i) => (
                                <div key={i} style={{ padding: '8px 0', borderBottom: '1px solid #eee' }}>
                                    <b>{log.time}</b> — {log.staff}: №{log.roomId} ({log.action})
                                </div>
                            ))}
                        </div>
                    </div>
                </>
            )}

            {/* Вкладка АРХИВ */}
            {view === 'archive' && (
                <div className="admin-settings-section fade-in">
                    <h3>История за 00:00</h3>
                    {archive.map((item, idx) => (
                        <div key={idx} style={{ padding: '10px', borderBottom: '1px solid #eee' }}>
                            <b>{item.date}</b>: ✅{item.stats.checked} | 🛑{item.stats.dnd}
                        </div>
                    ))}
                </div>
            )}

            {/* Вкладка ПЕРСОНАЛ */}
            {view === 'users' && (
                <div className="admin-settings-section fade-in">
                    <h3>Управление доступом</h3>

                    {/* Форма добавления */}
                    <div style={{ background: '#f9f9f9', padding: '15px', borderRadius: '10px', marginBottom: '20px' }}>
                        <input
                            className="search-input" style={{ marginBottom: '10px' }}
                            placeholder="Новый логин"
                            value={newUser.login}
                            onChange={(e) => setNewUser({...newUser, login: e.target.value})}
                        />
                        <input
                            className="search-input" style={{ marginBottom: '10px' }}
                            placeholder="Пароль"
                            value={newUser.pass}
                            onChange={(e) => setNewUser({...newUser, pass: e.target.value})}
                        />
                        <select
                            className="search-input" style={{ marginBottom: '10px' }}
                            value={newUser.role}
                            onChange={(e) => setNewUser({...newUser, role: e.target.value})}
                        >
                            <option value="staff">Staff (Горничная)</option>
                            <option value="supervisor">Supervisor (Админ)</option>
                        </select>
                        <button className="btn-check" onClick={addUser} style={{ padding: '10px' }}>ДОБАВИТЬ</button>
                    </div>

                    {/* Список пользователей */}
                    <div style={{ maxHeight: '200px', overflowY: 'auto' }}>
                        {users.map((u, i) => (
                            <div key={i} style={{ display: 'flex', justifyContent: 'space-between', padding: '10px', borderBottom: '1px solid #eee' }}>
                                <div>
                                    <b>{u.login}</b> <span style={{ fontSize: '10px', color: '#999' }}>({u.role})</span>
                                    <div style={{ fontSize: '11px', color: '#gold' }}>Пароль: {u.pass}</div>
                                </div>
                                {u.login !== 'admin' && (
                                    <button onClick={() => deleteUser(u.login)} style={{ color: 'red', border: 'none', background: 'none', cursor: 'pointer' }}>Удалить</button>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default AdminPanel;
